// Get configuration from the Configuration node
const config = $('Configuration').first().json;
const includeSourceLink = config.includeSourceLink;
const MAX_TITLE_LENGTH = config.maxTitleLength || 100;

// Get the post data from the Loop Over Items node
const caption = $('Loop Over Items').item.json.caption || '';
const postId = $('Loop Over Items').item.json.id;
const mediaUrl = $('Loop Over Items').item.json.media_url;
const permalink = $('Loop Over Items').item.json.permalink;

// Extract hashtags
const hashtagRegex = /#[\w\u00C0-\u024F]+/gu;
const hashtags = caption.match(hashtagRegex) || [];

// Get text before first hashtag
const firstHashtagIndex = caption.indexOf('#');
let textBeforeHashtags = firstHashtagIndex === -1 
  ? caption.trim() 
  : caption.substring(0, firstHashtagIndex).trim();

// Build title
let title = textBeforeHashtags;

// If no text before hashtags, use first hashtag
if (!title && hashtags.length > 0) {
  title = hashtags[0].replace('#', '');
}

// If still no title, use generic
if (!title) {
  title = 'Instagram Video';
}

// Smart truncation at word boundary
if (title.length > MAX_TITLE_LENGTH) {
  title = title.substring(0, MAX_TITLE_LENGTH);
  const lastSpace = title.lastIndexOf(' ');
  if (lastSpace > MAX_TITLE_LENGTH * 0.6) {
    title = title.substring(0, lastSpace);
  }
  title = title.trim() + '...';
}

// Build description - conditionally include source link
let description = caption;

if (includeSourceLink) {
  description += `\n\n---\nOriginally posted on Instagram: ${permalink}`;
}

// Extract tags for YouTube (without # symbol, max 10)
const tags = hashtags
  .map(h => h.replace('#', ''))
  .filter(t => t.length > 1 && t.length <= 30)
  .slice(0, 10);

// Return processed data
return [{
  json: {
    postId: postId,
    title: title,
    description: description,
    tags: tags,
    mediaUrl: mediaUrl,
    originalCaption: caption,
    hashtagCount: hashtags.length,
    sourceLinkIncluded: includeSourceLink
  }
}];
